      options: [{ id: `A`, text: `To compare the urban populations of two different countries` }, { id: `B`, text: `To explain why researchers are interested in studying global urbanization` }, { id: `C`, text: `To illustrate a problem faced by researchers studying global urbanization` }, { id: `D`, text: `To object to a method that some countries use to classify different types of settlements` }],
      answer: `C`,
