      prompt: `Which choice most effectively uses data from the graph to complete the statement?`,
      options: [{ id: `A`, text: `more volcanoes that have been active since 1960 than Guatemala has.` }, { id: `B`, text: `the same number of volcanoes that have been active since 1800 as Guatemala has.` }, { id: `C`, text: `no volcanoes that have been active since 1800.` }, { id: `D`, text: `fewer volcanoes that have been active since 1960 than Guatemala has.` }],
